\section*{Análise dos Distratores}

\begin{itemize}
  \item \textbf{Alternativa A:} Tecido ósseo
    \begin{itemize}
      \item Raciocínio provavel: considerar o tecido ósseo como local de armazenamento por sua estabilidade.
      \item Tipo de equívoco: confusão sobre composição tecidual.
      \item Razão da plausibilidade: o tecido ósseo parece um depósito pela sua rigidez e função estrutural.
      \item Por que está errado: o tecido ósseo não é rico em lipídios, não acumulando poluentes lipossolúveis preferencialmente.
    \end{itemize}
  \item \textbf{Alternativa B:} Tecido nervoso
    \begin{itemize}
      \item Raciocínio provável: presumir acúmulo devido à bainha de mielina rica em lipídios.
      \item Tipo de equívoco: generalização.
      \item Razão da plausibilidade: bainha de mielina contém lipídios, o que sugere possível bioacumulação.
      \item Por que está errado: quantidade total de lipídios no tecido nervoso é menor que no tecido adiposo.
    \end{itemize}
  \item \textbf{Alternativa C:} Tecido epitelial
    \begin{itemize}
      \item Raciocínio provável: pensar no contato direto com o ambiente como local de acúmulo.
      \item Tipo de equívoco: confusão entre função e composição.
      \item Razão da plausibilidade: é a interface com o meio externo.
      \item Por que está errado: tecido epitelial possui baixo teor lipídico, não acumulando poluentes lipossolúveis.
    \end{itemize}
  \item \textbf{Alternativa E:} Tecido sanguíneo
    \begin{itemize}
      \item Raciocínio provável: confundir transporte pelo sangue com acúmulo.
      \item Tipo de equívoco: confusão entre transporte e acumulação.
      \item Razão da plausibilidade: o sangue transporta poluentes pela circulação.
      \item Por que está errado: sangue não armazena poluentes lipossolúveis.
    \end{itemize}
\end{itemize}

